17	    /// All mutable UI state for the pack editor panel.
18	    pub struct PackEditorState {
19	        pub editor: PackEditor,
20	        pub profile_dir: PathBuf,
21	        pub selected_category: Option<String>,
22	        pub selected_macro: Option<String>,
23	        /// Form input: macro name.
24	        pub form_name: String,
25	        /// Form input: trigger phrase.
26	        pub form_phrase: String,
27	        /// Form input: if_flag gate condition.
28	        pub form_if_flag: String,
29	        /// Form input: set_flag side effect.
30	        pub form_set_flag: String,
31	        /// Form input: comma-separated key sequence.
32	        pub form_keys: String,
33	        /// True while the category rename confirmation UI is visible.
34	        pub show_rename_warning: bool,
35	        /// Last synchronous error to surface inline in the panel.
36	        pub last_error: Option<String>,
37	    }
38	
39	    impl PackEditorState {
40	        pub fn new(editor: PackEditor, profile_dir: PathBuf) -> Self {
41	            Self {
42	                editor,
43	                profile_dir,
44	                selected_category: None,
45	                selected_macro: None,
46	                form_name: String::new(),
47	                form_phrase: String::new(),
48	                form_if_flag: String::new(),
49	                form_set_flag: String::new(),
50	                form_keys: String::new(),
51	                show_rename_warning: false,
52	                last_error: None,
53	            }
54	        }
55	    }
56	
57	    /// Stub panel — renders a placeholder heading and the loaded pack name.
58	    /// Subsequent tasks fill in the full form UI.
59	    pub fn show_pack_editor(ui: &mut egui::Ui, state: &mut PackEditorState) {
60	        ui.heading("Pack Editor");
61	        ui.label(format!("Pack: {}", state.editor.pack().name));
62	
63	        if let Some(err) = &state.last_error.clone() {
64	            ui.colored_label(egui::Color32::RED, format!("Error: {err}"));
65	        }
66	    }
67	}
