69	// ── Key-sequence parser (pure logic — no gui feature required) ────────────────
70	
71	use crate::config::KeyAction;
72	use anyhow::{bail, Result};
73	
74	/// Parse a comma-separated key sequence string into a `Vec<KeyAction>`.
75	///
76	/// Each token is trimmed of whitespace and becomes a `KeyAction` with `dwell_ms`
77	/// and `gap_ms` left as `None` (inheriting global timing defaults).
78	/// Returns an error if the input is empty or any token is empty after trimming.
79	pub fn parse_key_sequence(input: &str) -> Result<Vec<KeyAction>> {
80	    if input.trim().is_empty() {
81	        bail!("key sequence must not be empty");
82	    }
83	
84	    let mut actions = Vec::new();
85	    for token in input.split(',') {
86	        let key = token.trim().to_string();
87	        if key.is_empty() {
88	            bail!("key sequence contains an empty token (check for trailing commas)");
89	        }
90	        actions.push(KeyAction { key, dwell_ms: None, gap_ms: None });
91	    }
92	
93	    Ok(actions)
94	}
