99	mod tests {
100	    use super::parse_key_sequence;
101	
102	    #[test]
103	    fn parse_key_sequence_single() {
104	        let result = parse_key_sequence("KEY_W").unwrap();
105	        assert_eq!(result.len(), 1);
106	        assert_eq!(result[0].key, "KEY_W");
107	        assert!(result[0].dwell_ms.is_none());
108	        assert!(result[0].gap_ms.is_none());
109	    }
110	
111	    #[test]
112	    fn parse_key_sequence_multiple_with_whitespace() {
113	        let result = parse_key_sequence("KEY_W , KEY_A , KEY_S").unwrap();
114	        assert_eq!(result.len(), 3);
115	        assert_eq!(result[0].key, "KEY_W");
116	        assert_eq!(result[1].key, "KEY_A");
117	        assert_eq!(result[2].key, "KEY_S");
118	    }
119	
120	    #[test]
121	    fn parse_key_sequence_empty_errors() {
122	        let err = parse_key_sequence("").unwrap_err();
123	        assert!(err.to_string().contains("empty"), "error must mention empty input");
124	    }
125	
126	    #[test]
127	    fn parse_key_sequence_trailing_comma() {
128	        let err = parse_key_sequence("KEY_W,").unwrap_err();
129	        assert!(
130	            err.to_string().contains("empty token"),
131	            "error must mention empty token for trailing comma"
132	        );
133	    }
