158	/// Return the XDG profiles directory (`$XDG_CONFIG_HOME/vibe-attack/profiles`), creating it if absent.
159	pub fn get_profiles_dir() -> Result<PathBuf> {
160	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
161	    let config_home = xdg.get_config_home()
162	        .context("Failed to determine config directory")?;
163	    let dir = config_home.join("profiles");
164	    std::fs::create_dir_all(&dir)?;
165	    Ok(dir)
166	}
