168	/// Partial-update descriptor for [`PackEditor::edit_macro`].
169	///
170	/// `None` for a field means "leave unchanged". `Some(None)` clears an optional field.
171	/// `Some(Some(v))` sets the field to `v`. The `keys` field replaces the entire vec when `Some`.
172	#[derive(Debug, Clone, Default)]
173	pub struct MacroUpdates {
174	    pub phrase: Option<Option<String>>,
175	    pub if_flag: Option<Option<String>>,
176	    pub set_flag: Option<Option<String>>,
177	    pub sound: Option<Option<PathBuf>>,
178	    pub keys: Option<Vec<KeyAction>>,
179	}
180	
181	/// Mutable wrapper around a [`Pack`] that enforces invariants on every CRUD operation.
182	///
183	/// Macro name uniqueness is enforced within a category, not globally.
184	pub struct PackEditor {
185	    pack: Pack,
186	}
187	
188	impl PackEditor {
189	    pub fn new(pack: Pack) -> Self {
190	        Self { pack }
191	    }
192	
193	    pub fn pack(&self) -> &Pack {
194	        &self.pack
195	    }
196	
197	    pub fn into_pack(self) -> Pack {
198	        self.pack
199	    }
200	
201	    /// Append `macro_config` to the end of the named category's macro list.
202	    ///
203	    /// Errors if `category` does not exist or if a macro with the same name is already present.
204	    pub fn add_macro(&mut self, category: &str, macro_config: MacroConfig) -> Result<()> {
205	        let cat = self
206	            .pack
207	            .categories
208	            .iter_mut()
209	            .find(|c| c.name == category)
210	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", category))?;
211	
212	        if cat.macros.iter().any(|m| m.name == macro_config.name) {
213	            bail!(
214	                "macro '{}' already exists in category '{}'",
215	                macro_config.name,
216	                category
217	            );
218	        }
219	
220	        cat.macros.push(macro_config);
221	        Ok(())
222	    }
223	
224	    /// Apply `updates` to the named macro in `category`, leaving all other fields unchanged.
225	    ///
226	    /// Errors if `category` or `macro_name` is not found.
227	    pub fn edit_macro(
228	        &mut self,
229	        category: &str,
230	        macro_name: &str,
231	        updates: MacroUpdates,
232	    ) -> Result<()> {
233	        let cat = self
234	            .pack
235	            .categories
236	            .iter_mut()
237	            .find(|c| c.name == category)
238	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", category))?;
239	
240	        let m = cat
241	            .macros
242	            .iter_mut()
243	            .find(|m| m.name == macro_name)
244	            .ok_or_else(|| {
245	                anyhow::anyhow!("macro '{}' not found in category '{}'", macro_name, category)
246	            })?;
247	
248	        if let Some(phrase) = updates.phrase {
249	            m.phrase = phrase;
250	        }
251	        if let Some(if_flag) = updates.if_flag {
252	            m.if_flag = if_flag;
253	        }
254	        if let Some(set_flag) = updates.set_flag {
255	            m.set_flag = set_flag;
256	        }
257	        if let Some(sound) = updates.sound {
258	            m.sound = sound;
259	        }
260	        if let Some(keys) = updates.keys {
261	            m.keys = keys;
262	        }
263	
264	        Ok(())
265	    }
266	
267	    /// Remove the named macro from `category`.
268	    ///
269	    /// Errors if `category` or `macro_name` is not found.
270	    pub fn remove_macro(&mut self, category: &str, macro_name: &str) -> Result<()> {
271	        let cat = self
272	            .pack
273	            .categories
274	            .iter_mut()
275	            .find(|c| c.name == category)
276	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", category))?;
277	
278	        let idx = cat
279	            .macros
280	            .iter()
281	            .position(|m| m.name == macro_name)
282	            .ok_or_else(|| {
283	                anyhow::anyhow!("macro '{}' not found in category '{}'", macro_name, category)
284	            })?;
285	
286	        cat.macros.remove(idx);
287	        Ok(())
288	    }
289	
290	    /// Move `macro_name` from `from_category` to the end of `to_category`.
291	    ///
292	    /// Atomic: validates all preconditions before any mutation.
293	    /// Errors if either category is missing, the macro is missing from source,
294	    /// or a macro with the same name already exists in the destination.
295	    pub fn move_macro(
296	        &mut self,
297	        from_category: &str,
298	        to_category: &str,
299	        macro_name: &str,
300	    ) -> Result<()> {
301	        // Validate preconditions before any mutation.
302	        let from_idx = self
303	            .pack
304	            .categories
305	            .iter()
306	            .position(|c| c.name == from_category)
307	            .ok_or_else(|| anyhow::anyhow!("source category '{}' not found", from_category))?;
308	
309	        let to_idx = self
310	            .pack
311	            .categories
312	            .iter()
313	            .position(|c| c.name == to_category)
314	            .ok_or_else(|| anyhow::anyhow!("destination category '{}' not found", to_category))?;
315	
316	        let macro_idx = self.pack.categories[from_idx]
317	            .macros
318	            .iter()
319	            .position(|m| m.name == macro_name)
320	            .ok_or_else(|| {
321	                anyhow::anyhow!(
322	                    "macro '{}' not found in category '{}'",
323	                    macro_name,
324	                    from_category
325	                )
326	            })?;
327	
328	        if self.pack.categories[to_idx]
329	            .macros
330	            .iter()
331	            .any(|m| m.name == macro_name)
332	        {
333	            bail!(
334	                "macro '{}' already exists in destination category '{}'",
335	                macro_name,
336	                to_category
337	            );
338	        }
339	
340	        // All checks passed — mutate atomically.
341	        let moved = self.pack.categories[from_idx].macros.remove(macro_idx);
342	        self.pack.categories[to_idx].macros.push(moved);
343	        Ok(())
344	    }
345	
346	    /// Rename `old_name` category to `new_name` in place (preserves index and macros).
347	    ///
348	    /// Errors if `old_name` is not found, if `new_name == old_name`, or if `new_name` is already in use.
349	    pub fn rename_category(&mut self, old_name: &str, new_name: &str) -> Result<()> {
350	        if old_name == new_name {
351	            bail!("new category name '{}' is identical to the old name", new_name);
352	        }
353	
354	        if self.pack.categories.iter().any(|c| c.name == new_name) {
355	            bail!("category '{}' already exists", new_name);
356	        }
357	
358	        let cat = self
359	            .pack
360	            .categories
361	            .iter_mut()
362	            .find(|c| c.name == old_name)
363	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", old_name))?;
364	
365	        cat.name = new_name.to_string();
366	        Ok(())
367	    }
368	
369	    /// Append a new empty category with `name` to the end of `pack.categories`.
370	    ///
371	    /// Errors if `name` is already in use.
372	    pub fn add_category(&mut self, name: &str) -> Result<()> {
373	        if self.pack.categories.iter().any(|c| c.name == name) {
374	            bail!("category '{}' already exists", name);
375	        }
376	
377	        self.pack.categories.push(Category {
378	            name: name.to_string(),
379	            macros: vec![],
380	        });
381	        Ok(())
382	    }
383	
384	    /// Remove the named category.
385	    ///
386	    /// Errors if `name` is not found or if the category still contains macros
387	    /// (caller must explicitly empty it first via `remove_macro`).
388	    pub fn remove_category(&mut self, name: &str) -> Result<()> {
389	        let idx = self
390	            .pack
391	            .categories
392	            .iter()
393	            .position(|c| c.name == name)
394	            .ok_or_else(|| anyhow::anyhow!("category '{}' not found", name))?;
395	
396	        if !self.pack.categories[idx].macros.is_empty() {
397	            bail!(
398	                "category '{}' still has {} macro(s); empty it first",
399	                name,
400	                self.pack.categories[idx].macros.len()
401	            );
402	        }
403	
404	        self.pack.categories.remove(idx);
405	        Ok(())
406	    }
407	}
