155	struct VibeAttackConfigApp {
156	    first_run: FirstRunState,
157	    config: ConfigApp,
158	    ptt: PttCaptureState,
159	    dl: ModelDownloadState,
160	    uinput: UinputSetupState,
161	    config_example_contents: &'static str,
162	    hd2_profile_contents: &'static str,
163	    mic: MicLevelState,
164	    log_rx: mpsc::Receiver<String>,
165	    setup_just_completed: bool,
166	    tray: Option<TrayHandle>,
167	    /// Cached full Config for round-trip saves; populated at startup or wizard-complete.
168	    cached_config: Option<vibe_attack::config::Config>,
169	    /// Input device names enumerated once at startup; empty list on CPAL failure.
170	    device_names: Vec<String>,
171	    /// Active pack editor state; `None` until a profile is clicked.
172	    pack_editor: Option<PackEditorState>,
173	}
174	
175	impl VibeAttackConfigApp {
176	    fn new(log_rx: mpsc::Receiver<String>) -> Self {
177	        use cpal::traits::{DeviceTrait, HostTrait};
178	
179	        let config_example_contents =
180	            include_str!(concat!(env!("CARGO_MANIFEST_DIR"), "/config.example.yaml"));
181	        let hd2_profile_contents =
182	            include_str!(concat!(env!("CARGO_MANIFEST_DIR"), "/profiles/hd2/pack.yaml"));
183	
184	        let first_run = probe::run();
185	        let setup_complete = first_run.is_setup_complete();
186	
187	        let mut config = ConfigApp::new();
188	        let mic;
189	
190	        // Enumerate input device names once at startup; degrade gracefully on failure.
191	        let device_names: Vec<String> = cpal::default_host()
192	            .input_devices()
193	            .map(|iter| iter.filter_map(|d| d.name().ok()).collect())
194	            .unwrap_or_default();
195	
196	        let mut cached_config = None;
197	
198	        if setup_complete {
199	            config.profiles = load_profiles();
200	            mic = spawn_mic_level_thread();
201	
202	            match load_config_into_app(&mut config, None) {
203	                Ok(cfg) => cached_config = Some(cfg),
204	                Err(e) => config.set_status(format!("Could not load config.yaml: {e}")),
205	            }
206	        } else {
207	            // Defer mic/profile load until after wizard completes
208	            mic = MicLevelState {
209	                level: Arc::new(AtomicU32::new(0)),
210	                no_device: false,
211	                _handle: None,
212	            };
213	        }
214	
215	        Self {
216	            first_run,
217	            config,
218	            ptt: PttCaptureState::new(),
219	            dl: ModelDownloadState::new(),
220	            uinput: UinputSetupState::new(),
221	            config_example_contents,
222	            hd2_profile_contents,
223	            mic,
224	            log_rx,
225	            setup_just_completed: false,
226	            tray: TrayHandle::spawn(),
227	            cached_config,
228	            device_names,
229	            pack_editor: None,
230	        }
231	    }
232	}
