234	impl eframe::App for VibeAttackConfigApp {
235	    fn ui(&mut self, ui: &mut egui::Ui, _frame: &mut eframe::Frame) {
236	        let ctx = ui.ctx().clone();
237	
238	        // Honour "Open Config" requests from the tray.
239	        if self.tray.as_ref().is_some_and(|t| t.take_open_request()) {
240	            ctx.send_viewport_cmd(egui::ViewportCommand::Focus);
241	        }
242	
243	        // Repaint at ~10Hz for mic level updates when in main config view.
244	        if self.first_run.is_setup_complete() {
245	            ctx.request_repaint_after(std::time::Duration::from_millis(100));
246	        }
247	
248	        // Repaint faster while PTT capture thread is listening.
249	        if self.ptt.listening {
250	            ctx.request_repaint_after(std::time::Duration::from_millis(50));
251	        }
252	
253	        // Repaint while model download is in progress.
254	        if self.dl.is_running() {
255	            ctx.request_repaint_after(std::time::Duration::from_millis(250));
256	        }
257	
258	        // Repaint while uinput setup actions are running.
259	        use vibe_attack::ui::wizard::SetupActionStatus;
260	        if matches!(self.uinput.modprobe, SetupActionStatus::Running)
261	            || matches!(self.uinput.usermod, SetupActionStatus::Running)
262	        {
263	            ctx.request_repaint_after(std::time::Duration::from_millis(200));
264	        }
265	
266	        // Drain log channel.
267	        while let Ok(line) = self.log_rx.try_recv() {
268	            self.config.add_log_line(line);
269	        }
270	
271	        // Update mic level from atomic.
272	        self.config.mic_level = self.mic.current_level();
273	        self.config.mic_no_device = self.mic.no_device;
274	
275	        // Refresh daemon-running status each frame (cheap socket stat).
276	        self.config.daemon_running = vibe_attack::control::client::is_daemon_running();
277	
278	        // Detect wizard completion and load profiles + start mic thread.
279	        if self.setup_just_completed {
280	            self.setup_just_completed = false;
281	            self.config.profiles = load_profiles();
282	            self.mic = spawn_mic_level_thread();
283	
284	            match load_config_into_app(&mut self.config, None) {
285	                Ok(cfg) => self.cached_config = Some(cfg),
286	                Err(e) => self.config.set_status(format!("Could not load config.yaml: {e}")),
287	            }
288	        }
289	
290	        ui.heading("Vibe Attack");
291	        ui.separator();
292	
293	        let was_incomplete = !self.first_run.is_setup_complete();
294	
295	        if !self.first_run.is_setup_complete() {
296	            show_wizard(
297	                ui,
298	                &mut self.first_run,
299	                &mut self.ptt,
300	                &mut self.dl,
301	                &mut self.uinput,
302	                self.config_example_contents,
303	                self.hd2_profile_contents,
304	            );
305	            // Detect transition to complete
306	            if was_incomplete && self.first_run.is_setup_complete() {
307	                self.setup_just_completed = true;
308	            }
309	        } else {
310	            show_main_config(ui, self);
311	        }
312	    }
313	}
314	
315	fn show_main_config(ui: &mut egui::Ui, app: &mut VibeAttackConfigApp) {
316	    // Daemon status row
317	    ui.horizontal(|ui| {
318	        if app.config.daemon_running {
319	            ui.colored_label(egui::Color32::GREEN, "● Daemon: running");
320	        } else {
321	            ui.colored_label(
322	                egui::Color32::from_rgb(255, 165, 0),
323	                "● Daemon: not running (changes will save to disk only)",
324	            );
325	        }
326	    });
327	
328	    ui.add_space(4.0);
329	
330	    // Mic level row
331	    ui.horizontal(|ui| {
332	        ui.label("Mic:");
333	        if app.config.mic_no_device {
334	            ui.label("no device");
335	        } else {
336	            ui.add(
337	                egui::ProgressBar::new(app.config.mic_level.clamp(0.0, 1.0))
338	                    .desired_width(200.0)
339	                    .show_percentage(),
340	            );
341	        }
342	    });
343	
344	    ui.add_space(4.0);
345	
346	    // Activation mode
347	    ui.horizontal(|ui| {
348	        ui.label("Mode:");
349	        ui.radio_value(&mut app.config.mode, ActivationMode::Ptt, "Push-to-talk");
350	        ui.radio_value(&mut app.config.mode, ActivationMode::Wake, "Wake word");
351	    });
352	
353	    // Confidence threshold slider
354	    ui.add(
355	        egui::Slider::new(&mut app.config.threshold_pct, 0u8..=100u8)
356	            .text("Confidence threshold (%)"),
357	    );
358	
359	    // Input device combo box
360	    let current_device_label = app
361	        .config
362	        .input_device
363	        .as_deref()
364	        .unwrap_or("<system default>")
365	        .to_string();
366	    egui::ComboBox::from_label("Input device")
367	        .selected_text(current_device_label)
368	        .show_ui(ui, |ui| {
369	            // Leading option: system default (maps to None)
370	            let is_default = app.config.input_device.is_none();
371	            if ui.selectable_label(is_default, "<system default>").clicked() {
372	                app.config.input_device = None;
373	            }
374	            for name in &app.device_names.clone() {
375	                let is_selected = app.config.input_device.as_deref() == Some(name.as_str());
376	                if ui.selectable_label(is_selected, name.as_str()).clicked() {
377	                    app.config.input_device = Some(name.clone());
378	                }
379	            }
380	        });
381	
382	    // PTT binding (read-only display — live capture deferred to post-S01)
383	    ui.horizontal(|ui| {
384	        ui.label(format!("PTT key: {}", app.config.ptt_binding));
385	    });
386	
387	    // Save button
388	    if ui.button("Save").clicked() {
389	        handle_save(app);
390	    }
391	
392	    // Status message
393	    if let Some(msg) = &app.config.status_message.clone() {
394	        ui.label(msg);
395	    }
396	
397	    ui.add_space(8.0);
398	
399	    // Profiles list
400	    ui.label(format!("Profiles ({})", app.config.profile_count()));
401	    if app.config.profiles.is_empty() {
402	        ui.weak("No profiles found in ~/.config/vibe-attack/profiles/");
403	    } else {
404	        for name in &app.config.profiles.clone() {
405	            let is_active = app.config.active_profile.as_deref() == Some(name.as_str());
406	            let is_editing = app
407	                .pack_editor
408	                .as_ref()
409	                .map(|s| s.editor.pack().name == *name)
410	                .unwrap_or(false);
411	            if ui.selectable_label(is_active || is_editing, name.as_str()).clicked() {
412	                match vibe_attack::pack::get_profiles_dir() {
413	                    Ok(profiles_dir) => {
414	                        let profile_dir = profiles_dir.join(name);
415	                        match vibe_attack::pack::Pack::load_from_dir(&profile_dir) {
416	                            Ok(pack) => {
417	                                let editor = vibe_attack::pack::PackEditor::new(pack);
418	                                app.pack_editor =
419	                                    Some(PackEditorState::new(editor, profile_dir));
420	                            }
421	                            Err(e) => {
422	                                tracing::warn!(profile = %name, reason = %e, "Failed to load pack for editor");
423	                            }
424	                        }
425	                    }
426	                    Err(e) => {
427	                        tracing::warn!(reason = %e, "Failed to resolve profiles dir for pack editor");
428	                    }
429	                }
430	            }
431	        }
432	    }
433	
434	    if let Some(editor_state) = app.pack_editor.as_mut() {
435	        ui.add_space(8.0);
436	        ui.separator();
437	        show_pack_editor(ui, editor_state);
438	    }
439	
440	    ui.separator();
441	    ui.label("Log:");
442	    egui::ScrollArea::vertical()
443	        .auto_shrink([false, false])
444	        .stick_to_bottom(true)
445	        .show(ui, |ui| {
446	            for line in &app.config.log_lines.clone() {
447	                ui.monospace(line.as_str());
448	            }
449	        });
450	}
451	
452	fn handle_save(app: &mut VibeAttackConfigApp) {
453	    use vibe_attack::control::client::send_command;
454	    use vibe_attack::control::protocol::ControlRequest;
455	
456	    let Some(cached) = app.cached_config.as_ref() else {
457	        app.config.set_status("No config loaded — cannot save.");
458	        return;
459	    };
460	
461	    match save_app_to_config(&app.config, cached, None) {
462	        Err(e) => {
463	            app.config.set_status(format!("Save failed: {e}"));
464	            return;
465	        }
466	        Ok(updated) => {
467	            app.cached_config = Some(updated);
468	        }
469	    }
470	
471	    if !app.config.daemon_running {
472	        app.config
473	            .set_status("Saved to disk — daemon not running, runtime changes skipped.");
474	        return;
475	    }
476	
477	    // Dispatch four control commands; collect any failures.
478	    let commands = [
479	        ControlRequest::SetMode { mode: app.config.mode.clone() },
480	        ControlRequest::SetThreshold {
481	            threshold: app.config.threshold_pct as f32 / 100.0,
482	        },
483	        ControlRequest::SetInputDevice {
484	            device: app.config.input_device.clone(),
485	        },
486	        ControlRequest::SetPttBinding {
487	            key: app.config.ptt_binding.clone(),
488	        },
489	    ];
490	
491	    let mut errors: Vec<String> = Vec::new();
492	    for cmd in commands {
493	        let label = format!("{cmd:?}");
494	        if let Err(e) = send_command(cmd) {
495	            errors.push(format!("Failed to send {label}: {e}"));
496	        }
497	    }
498	
499	    if errors.is_empty() {
500	        app.config.set_status("Saved and applied.");
501	    } else {
502	        app.config.set_status(errors.join("; "));
503	    }
504	}
505	
506	fn main() -> eframe::Result<()> {
507	    use tracing_subscriber::prelude::*;
508	
509	    // Log channel: bounded to 500 entries; oldest are dropped under pressure.
510	    let (log_tx, log_rx) = mpsc::sync_channel(500);
511	
512	    tracing_subscriber::registry()
513	        .with(tracing_subscriber::fmt::layer())
514	        .with(ChannelLayer { tx: log_tx })
515	        .init();
516	
517	    let options = eframe::NativeOptions {
518	        viewport: egui::ViewportBuilder::default()
519	            .with_title("Vibe Attack Config")
520	            .with_inner_size([720.0, 520.0]),
521	        ..Default::default()
522	    };
523	
524	    eframe::run_native(
525	        "Vibe Attack Config",
526	        options,
527	        Box::new(|_cc| Ok(Box::new(VibeAttackConfigApp::new(log_rx)))),
528	    )
529	}
